// Login.js
import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./Login.css";

function Login() {
  const [empld, setEmpld] = useState("");
  const [password, setPassword] = useState("");
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();

    try {
      // NOTE: backend expects empId key
      const res = await fetch(
        "https://prasa-app-yde3.onrender.com/api/auth/login",
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ empId: empld, password }),
        }
      );

      const data = await res.json();
      console.log("LOGIN RESPONSE:", data);

      if (!data || !data.success) {
        alert(data?.message || "Invalid login");
      } else {
        // save employee to localStorage so other components can read it
        // (your UI hasn't changed — they all expect employee prop; you can read from localStorage)
        localStorage.setItem("prasa_employee", JSON.stringify(data.employee));
        navigate("/home");
      }
    } catch (err) {
      console.error("Login Error:", err);
      alert("Server error");
    }
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">
        <div className="logo-container">
          <img src="/logo192.png" alt="Prasa Logo" className="login-logo" />
        </div>

        <h2 className="login-title">PRASA Employee Portal</h2>

        <form onSubmit={handleLogin}>
          <input
            type="text"
            className="input-box"
            placeholder="EMP ID"
            value={empld}
            onChange={(e) => setEmpld(e.target.value)}
          />

          <input
            type="password"
            className="input-box"
            placeholder="Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />

          <button type="submit" className="btn-login">
            Login
          </button>
        </form>
      </div>
    </div>
  );
}

export default Login;
